import React from "react";
import { useState } from "react";
import "./nav.css";

export default function Nav() {
  const [Active, IsActive] = useState("off");
  const [Answear, setAnswear] = useState("off");
  const handleClick = () => {
    if (Active === "off") {
      IsActive("true");
    } else {
      IsActive("off");
    }
  };

  return (
    <div>
      <div
        value={Answear}
        onChange={handleTextareaChange}
        className="pushMenu"
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}
function handleTextareaChange(e) {
  setAnswear(e.target.value);
}

